#include <bits/stdc++.h>
using namespace std;

const int INF = (1 << 31) - 1;

int dp[1000005], coins[10] = {
    1, 5, 11
};

int main() {
    int n;
    cin >> n;
    dp[0] = 0;
    for (int i = 1; i <= n; i++) {
        dp[i] = INF;
        for (int j = 0; j < 3; j++) {
            if (i - coins[j] >= 0) {
                dp[i] = min(dp[i], dp[i - coins[j]] + 1);
            }
            else {
                break;
            }
        }
    }
    cout << dp[n];
}
